from fractions import Fraction
class Solution:
    def minSkips(self, dist, speed, hoursBefore):
        # Independent: exact rational arrival times, no scaling trick.
        n = len(dist)
        INF = None
        # dp[j] = min exact arrival time (Fraction) using exactly j skips so far
        dp = [None] * (n + 1)
        dp[0] = Fraction(0)
        for i in range(n):
            travel = Fraction(dist[i], speed)
            ndp = [None] * (n + 1)
            last = (i == n - 1)
            for j in range(i + 1):
                if dp[j] is None:
                    continue
                t = dp[j] + travel
                if last:
                    arrive = t
                else:
                    # round up to next integer hour
                    if t.denominator == 1:
                        arrive = t
                    else:
                        arrive = Fraction(t.numerator // t.denominator + 1)
                if ndp[j] is None or arrive < ndp[j]:
                    ndp[j] = arrive
                # skip this rest: keep fractional arrival, one more skip
                if ndp[j + 1] is None or t < ndp[j + 1]:
                    ndp[j + 1] = t
            dp = ndp
        target = Fraction(hoursBefore)
        for j in range(n + 1):
            if dp[j] is not None and dp[j] <= target:
                return j
        return -1

