class Solution:
    def minSkips(self, dist, speed, hoursBefore):
        n = len(dist)
        INF = float('inf')
        # dp[j] = min scaled (by speed) arrival time using j skips
        dp = [0] + [INF] * n
        for i in range(n):
            d = dist[i]
            ndp = [INF] * (n + 1)
            last = (i == n - 1)
            for j in range(i + 1):
                if dp[j] == INF:
                    continue
                t = dp[j] + d
                if last:
                    if t < ndp[j]:
                        ndp[j] = t
                else:
                    rest = -(-t // speed) * speed
                    if rest < ndp[j]:
                        ndp[j] = rest
                if t < ndp[j + 1]:
                    ndp[j + 1] = t
            dp = ndp
        limit = hoursBefore * speed
        for j in range(n + 1):
            if dp[j] <= limit:
                return j
        return -1

