var minSkips = function(dist, speed, hoursBefore) {
    const n = dist.length;
    const INF = Infinity;
    let dp = new Array(n + 1).fill(INF);
    dp[0] = 0;
    for (let i = 0; i < n; i++) {
        const d = dist[i];
        const ndp = new Array(n + 1).fill(INF);
        const last = (i === n - 1);
        for (let j = 0; j <= i; j++) {
            if (dp[j] === INF) continue;
            const t = dp[j] + d;
            if (last) {
                if (t < ndp[j]) ndp[j] = t;
            } else {
                const rest = Math.ceil(t / speed) * speed;
                if (rest < ndp[j]) ndp[j] = rest;
            }
            if (t < ndp[j + 1]) ndp[j + 1] = t;
        }
        dp = ndp;
    }
    const limit = hoursBefore * speed;
    for (let j = 0; j <= n; j++) {
        if (dp[j] <= limit) return j;
    }
    return -1;
};
